double totalCesta = 0; double totalLimpeza = 0; double totalAlimentacao = 0; double totalHigiene = 0; double preco; char codigo; for (int i = 1; i <= 20; i++) { Console.WriteLine($"Produto {i}"); Console.Write("Digite o preço: "); preco = double.Parse(Console.ReadLine()); Console.Write("Digite o código (L/A/H): "); codigo = char.Parse(Console.ReadLine()); totalCesta += preco; if (codigo == 'l' || codigo == 'L') { totalLimpeza += preco; } else if (codigo == 'a' || codigo == 'A') { totalAlimentacao += preco; } else if (codigo == 'h' || codigo == 'H') { totalHigiene += preco; } } Console.WriteLine("\nTotal da cesta básica:"); Console.WriteLine($"R$ {totalCesta}"); Console.WriteLine("\nTotal por categoria:"); Console.WriteLine($"Limpeza: R$ {totalLimpeza}"); Console.WriteLine($"Alimentação: R$ {totalAlimentacao}"); Console.WriteLine($"Higiene: R$ {totalHigiene}");
